_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec4 fragColor = 0;
// CONV: Center on screen, then try some uAspect correction
vUv = (vUv*2) - 1;
vUv *= uAspect.xy;
// CONV: Adjust this to flip the output (±vUv.x, ±vUv.y)
vUv = vec2(vUv.x, -vUv.y);
vec2 fragCoord  = vUv;


#ifdef AA
for(float x = 0.;x<1.;x+=1./float(AA)){
for(float y = 0.;y<1.;y+=1./float(AA)){
#else
const float AA=1.,x=0.,y=0.;
#endif

//vUv = (2.*(fragCoord+vec2(x,y))-vUv.xy)/vUv.y;

const float shutter_speed = .25; // for motion blur

//float dt = fract(texture(iChannel0,float(AA)*(fragCoord+vec2(x,y))/vUv.xy).r+uTime)*shutter_speed;

float dt = fract(hash21(float(AA)*(fragCoord+vec2(x,y)))+uTime)*shutter_speed;

jTime = uTime;

float fx = sin(uTime*0.3)*0.3;
#ifdef bass_smooth
float fy = 0.7+0.2*bass_smooth;
#else
float fy = sin(uTime*0.3)*0.3+1.1;
#endif
float fz = (-20000.+jTime*speed);
vec3 ro = vec3(fx,fy,fz);

#ifdef stereo
ro+=stereo*vec3(.2*(float(vUv.x>0.)-.5),0.,0.);
const float de = .9;
vUv.x=vUv.x+.5*(vUv.x>0.?-de:de);
vUv*=2.;
#endif
float dis = 1.2;
vec3 rd = normalize(vec3(vUv,dis));
//vec3 rd = normalize(vec3(vUv,sqrt(1.-dot(vUv,vUv))));

vec2 i = intersect(ro,rd);
float d = i.x;
float sunheight = .16;
float f1 = sunheight+.05*0.35*cos(jTime*0.1);
vec3 ld = normalize(vec3(0,f1,0.7));
vec3 fog = d>0.?exp2(-d*vec3(.14,.1,.28)):vec3(0,0,0);
vec3 sky = gsky(rd,ld,d<0.);

vec3 p = ro+d*rd;
vec3 n = normalize(grad(p));

float diff = dot(n,ld)+.1*n.y;
vec3 col = vec3(.1,.11,.18)*diff;

vec3 rfd = reflect(rd,n);
vec3 rfcol = gsky(rfd,ld,true);

// floor
//col = mix(col,rfcol,.05+.95*pow(max(1.+dot(rd,n),0.),5.));

float shiny = 0.88;
col = mix(col,rfcol,.05+.95*pow(max(1.+dot(rd,n),shiny),5.));

#ifdef VAPORWAVE
col = mix(col,vec3(.4,.5,1.),smoothstep(.05,.0,i.y));
col = mix(sky,col,fog);
col = sqrt(col);
#else
col = mix(col,vec3(.8,.1,.92),smoothstep(.05,0,i.y));
col = mix(sky,col,fog);
//no gamma for that old cg look
#endif

if(d<0.) d=1e6;
d=min(d,10.);

fragColor += vec4(clamp(col,0,1),d<0. ? 0 : 0.1+exp2(-d));

#ifdef AA
fragColor/=float(AA*AA);
}}
#endif
ret = fragColor;

  fragColor = ret;
}
